import{_ as t}from"./plugin-vue_export-helper-DlAUqK2U.js";import{c as o,a,e,r as l,o as d}from"./app-MOk6SBbl.js";const p={};function r(i,s){const n=l("Mermaid");return d(),o("div",null,[s[0]||(s[0]=a('<h2 id="引言" tabindex="-1"><a class="header-anchor" href="#引言"><span>引言</span></a></h2><blockquote><p>用户投诉&quot;APP 翻页越来越卡&quot;，一查才发现：翻到第 1000 页时，一条简单的分页查询要跑 <strong>3 秒</strong>。</p></blockquote><p><code>LIMIT 100000, 10</code>——这条看似无害的 SQL，在数据量增长后变成了性能杀手。MySQL 需要先扫描并丢弃前 10 万条数据，才能返回你需要的 10 条。数据量越大，性能下降越剧烈。</p><p>深分页是所有业务系统的必经之路：后台管理列表、日志查询、数据报表……都会遇到。本文总结三种实战验证过的优化方案，最高可将查询效率提升 <strong>数十倍</strong>。读完你将掌握：</p><ul><li>深分页性能骤降的底层原因（回表机制）</li><li>三种优化方案的适用场景和性能对比</li><li>互联网大厂瀑布流背后的分页技术选型</li></ul><hr><h2 id="一、深分页问题复现" tabindex="-1"><a class="header-anchor" href="#一、深分页问题复现"><span>一、深分页问题复现</span></a></h2><h3 id="_1-1-准备数据" tabindex="-1"><a class="header-anchor" href="#_1-1-准备数据"><span>1.1 准备数据</span></a></h3><p>创建用户表，仅在 <code>create_time</code> 字段上加索引：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> <span class="token identifier"><span class="token punctuation">`</span>user<span class="token punctuation">`</span></span> <span class="token punctuation">(</span>\n  <span class="token identifier"><span class="token punctuation">`</span>id<span class="token punctuation">`</span></span> <span class="token keyword">int</span> <span class="token operator">NOT</span> <span class="token boolean">NULL</span> <span class="token keyword">AUTO_INCREMENT</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;主键&#39;</span><span class="token punctuation">,</span>\n  <span class="token identifier"><span class="token punctuation">`</span>name<span class="token punctuation">`</span></span> <span class="token keyword">varchar</span><span class="token punctuation">(</span><span class="token number">255</span><span class="token punctuation">)</span> <span class="token keyword">DEFAULT</span> <span class="token boolean">NULL</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;姓名&#39;</span><span class="token punctuation">,</span>\n  <span class="token identifier"><span class="token punctuation">`</span>create_time<span class="token punctuation">`</span></span> <span class="token keyword">timestamp</span> <span class="token boolean">NULL</span> <span class="token keyword">DEFAULT</span> <span class="token boolean">NULL</span> <span class="token keyword">COMMENT</span> <span class="token string">&#39;创建时间&#39;</span><span class="token punctuation">,</span>\n  <span class="token keyword">PRIMARY</span> <span class="token keyword">KEY</span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">`</span>id<span class="token punctuation">`</span></span><span class="token punctuation">)</span><span class="token punctuation">,</span>\n  <span class="token keyword">KEY</span> <span class="token identifier"><span class="token punctuation">`</span>idx_create_time<span class="token punctuation">`</span></span> <span class="token punctuation">(</span><span class="token identifier"><span class="token punctuation">`</span>create_time<span class="token punctuation">`</span></span><span class="token punctuation">)</span>\n<span class="token punctuation">)</span> <span class="token keyword">ENGINE</span><span class="token operator">=</span><span class="token keyword">InnoDB</span> <span class="token keyword">COMMENT</span><span class="token operator">=</span><span class="token string">&#39;用户表&#39;</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_1-2-验证深分页问题" tabindex="-1"><a class="header-anchor" href="#_1-2-验证深分页问题"><span>1.2 验证深分页问题</span></a></h3><p><strong>查询第 1 页</strong>（每页 10 条）：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> \n<span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> \n<span class="token keyword">LIMIT</span> <span class="token number">0</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>执行结果：不到 0.01 秒，瞬间返回。</p><p><strong>查询第 10000 页</strong>：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> \n<span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> \n<span class="token keyword">LIMIT</span> <span class="token number">100000</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>执行结果：约 0.16 秒，性能下降 <strong>数十倍</strong>。</p><h3 id="_1-3-性能下降的根源" tabindex="-1"><a class="header-anchor" href="#_1-3-性能下降的根源"><span>1.3 性能下降的根源</span></a></h3><p>耗时主要花在两个环节：</p><ol><li><strong>大量数据扫描</strong>：需要扫描前 100010 条数据，找到符合条件的 100000 条并丢弃</li><li><strong>频繁回表查询</strong>：<code>create_time</code> 是非聚簇索引，每条数据都需要先通过二级索引找到主键 ID，再回表查询所有字段</li></ol><h3 id="_1-4-回表查询流程" tabindex="-1"><a class="header-anchor" href="#_1-4-回表查询流程"><span>1.4 回表查询流程</span></a></h3>',21)),e(n,{id:"mermaid-80",code:""}),e(n,{id:"mermaid-81",code:""}),s[1]||(s[1]=a(`<blockquote><p><strong>💡 核心提示</strong>：深分页的性能瓶颈 = 大量扫描 + 频繁回表。优化思路就是<strong>减少扫描行数</strong>和<strong>减少回表次数</strong>。</p></blockquote><h2 id="二、方案一-子查询优化-延迟关联" tabindex="-1"><a class="header-anchor" href="#二、方案一-子查询优化-延迟关联"><span>二、方案一：子查询优化（延迟关联）</span></a></h2><h3 id="_2-1-优化思路" tabindex="-1"><a class="header-anchor" href="#_2-1-优化思路"><span>2.1 优化思路</span></a></h3><p>先在子查询中只查询主键 ID（利用覆盖索引，无需回表），拿到 10 个 ID 后再回表查询完整数据。</p><h3 id="_2-2-优化-sql" tabindex="-1"><a class="header-anchor" href="#_2-2-优化-sql"><span>2.2 优化 SQL</span></a></h3><p>直接嵌套子查询会报错（MySQL 不支持子查询中使用 LIMIT），需要多套一层：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> 
<span class="token keyword">WHERE</span> id <span class="token operator">IN</span> <span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span> id <span class="token keyword">FROM</span> <span class="token punctuation">(</span>
        <span class="token keyword">SELECT</span> id <span class="token keyword">FROM</span> <span class="token keyword">user</span> 
        <span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> 
        <span class="token keyword">LIMIT</span> <span class="token number">100000</span><span class="token punctuation">,</span> <span class="token number">10</span>
    <span class="token punctuation">)</span> <span class="token keyword">AS</span> t
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_2-3-为什么能加速" tabindex="-1"><a class="header-anchor" href="#_2-3-为什么能加速"><span>2.3 为什么能加速？</span></a></h3><p>使用 <code>EXPLAIN</code> 查看执行计划，子查询的 <code>Extra</code> 列显示 <strong><code>Using index</code></strong>，表示用到了<strong>覆盖索引</strong>——只在二级索引中就能拿到主键 ID，无需回表。</p><table><thead><tr><th>对比项</th><th>原始 SQL</th><th>子查询优化</th></tr></thead><tbody><tr><td>扫描行数</td><td>100010</td><td>100010</td></tr><tr><td>回表次数</td><td><strong>100010</strong></td><td><strong>10</strong></td></tr><tr><td>执行时间</td><td>0.16 秒</td><td>0.05 秒</td></tr></tbody></table><p>回表次数从 100010 次降到 10 次，性能提升约 <strong>3 倍</strong>。</p><h3 id="_2-4-流程图" tabindex="-1"><a class="header-anchor" href="#_2-4-流程图"><span>2.4 流程图</span></a></h3>`,12)),e(n,{id:"mermaid-165",code:""}),s[2]||(s[2]=a(`<h2 id="三、方案二-inner-join-优化" tabindex="-1"><a class="header-anchor" href="#三、方案二-inner-join-优化"><span>三、方案二：INNER JOIN 优化</span></a></h2><h3 id="_3-1-优化-sql" tabindex="-1"><a class="header-anchor" href="#_3-1-优化-sql"><span>3.1 优化 SQL</span></a></h3><p>把子查询改成 INNER JOIN 关联查询：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> u<span class="token punctuation">.</span><span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> u
<span class="token keyword">INNER</span> <span class="token keyword">JOIN</span> <span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span> id <span class="token keyword">FROM</span> <span class="token keyword">user</span> 
    <span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> 
    <span class="token keyword">LIMIT</span> <span class="token number">100000</span><span class="token punctuation">,</span> <span class="token number">10</span>
<span class="token punctuation">)</span> <span class="token keyword">AS</span> t <span class="token keyword">ON</span> u<span class="token punctuation">.</span>id <span class="token operator">=</span> t<span class="token punctuation">.</span>id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_3-2-与子查询方案的对比" tabindex="-1"><a class="header-anchor" href="#_3-2-与子查询方案的对比"><span>3.2 与子查询方案的对比</span></a></h3><table><thead><tr><th>对比项</th><th>子查询</th><th>INNER JOIN</th></tr></thead><tbody><tr><td>性能</td><td>相同</td><td>相同</td></tr><tr><td>可读性</td><td>嵌套深</td><td>更直观</td></tr><tr><td>MySQL 优化器</td><td>转为派生表</td><td>直接使用派生表</td></tr><tr><td>推荐度</td><td>⭐⭐⭐</td><td>⭐⭐⭐⭐</td></tr></tbody></table><blockquote><p><strong>💡 核心提示</strong>：子查询和 INNER JOIN 本质是同一个优化思路——<strong>延迟关联（Deferred Join）</strong>，核心都是先通过覆盖索引拿到主键 ID，再回表。</p></blockquote><h2 id="四、方案三-分页游标-推荐" tabindex="-1"><a class="header-anchor" href="#四、方案三-分页游标-推荐"><span>四、方案三：分页游标（推荐）</span></a></h2><h3 id="_4-1-实现方式" tabindex="-1"><a class="header-anchor" href="#_4-1-实现方式"><span>4.1 实现方式</span></a></h3><p>记录上一页最后一条数据的位置，作为下一页的查询条件：</p><div class="language-sql line-numbers-mode" data-ext="sql" data-title="sql"><pre class="language-sql"><code><span class="token comment">-- 查询第一页</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> 
<span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> create_time<span class="token punctuation">,</span> id
<span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span>

<span class="token comment">-- 记住第一页最后一条的 id（假设为 100），查询第二页</span>
<span class="token keyword">SELECT</span> <span class="token operator">*</span> <span class="token keyword">FROM</span> <span class="token keyword">user</span> 
<span class="token keyword">WHERE</span> create_time <span class="token operator">&gt;</span> <span class="token string">&#39;2022-07-03&#39;</span> <span class="token operator">AND</span> id <span class="token operator">&gt;</span> <span class="token number">100</span> 
<span class="token keyword">ORDER</span> <span class="token keyword">BY</span> create_time<span class="token punctuation">,</span> id
<span class="token keyword">LIMIT</span> <span class="token number">10</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-2-为什么性能最好" tabindex="-1"><a class="header-anchor" href="#_4-2-为什么性能最好"><span>4.2 为什么性能最好？</span></a></h3><p>每次查询都从游标位置开始扫描，不需要跳过任何数据。无论翻到第几页，查询性能都<strong>稳定不变</strong>。</p><table><thead><tr><th>对比项</th><th>原始 SQL</th><th>子查询/JOIN</th><th>游标分页</th></tr></thead><tbody><tr><td>第 1 页耗时</td><td>0.01 秒</td><td>0.01 秒</td><td>0.01 秒</td></tr><tr><td>第 10000 页耗时</td><td>0.16 秒</td><td>0.05 秒</td><td><strong>&lt;0.01 秒</strong></td></tr><tr><td>扫描行数</td><td>100010</td><td>100010</td><td><strong>10</strong></td></tr><tr><td>回表次数</td><td>100010</td><td>10</td><td><strong>10</strong></td></tr><tr><td>性能提升</td><td>-</td><td>3x</td><td><strong>16x+</strong></td></tr></tbody></table><h3 id="_4-3-适用场景" tabindex="-1"><a class="header-anchor" href="#_4-3-适用场景"><span>4.3 适用场景</span></a></h3><table><thead><tr><th>场景</th><th>是否适合游标分页</th></tr></thead><tbody><tr><td>资讯类 APP 首页（瀑布流）</td><td>非常适合</td></tr><tr><td>社交媒体动态流</td><td>非常适合</td></tr><tr><td>后台管理列表（需要跳页）</td><td>不适合</td></tr><tr><td>数据报表（需要跳页）</td><td>不适合</td></tr></tbody></table><blockquote><p><strong>💡 核心提示</strong>：游标分页的代价是<strong>无法跳转到指定页</strong>，只能一页一页翻。但大部分互联网 APP（如头条、微博、小红书）的首页瀑布流，根本不需要跳页功能。</p></blockquote><h3 id="_4-4-大厂实践" tabindex="-1"><a class="header-anchor" href="#_4-4-大厂实践"><span>4.4 大厂实践</span></a></h3><p>以头条的瀑布流为例：</p>`,19)),e(n,{id:"mermaid-411",code:""}),s[3]||(s[3]=a('<h2 id="五、生产环境避坑指南" tabindex="-1"><a class="header-anchor" href="#五、生产环境避坑指南"><span>五、生产环境避坑指南</span></a></h2><ol><li><strong>永远不要在循环中做深分页</strong>：如果需要通过分页遍历全表数据，使用游标分页方案，避免 <code>LIMIT offset, size</code> 的性能退化。</li><li><code>LIMIT offset, size</code> <strong>中 offset 的陷阱</strong>：<code>LIMIT 100000, 10</code> 的 100000 不是第 100000 条，而是跳过 100000 条后取 10 条。offset 越大性能越差。</li><li><strong>覆盖索引是优化的关键</strong>：方案一和方案二的核心是利用覆盖索引减少回表次数。确保子查询中只查询索引字段（通常是主键 ID）。</li><li><strong>ORDER BY 必须与索引一致</strong>：游标分页要求 <code>ORDER BY</code> 的字段与索引顺序一致，否则无法利用索引排序，仍然会全表扫描。</li><li><strong>游标分页要注意排序字段唯一性</strong>：如果排序字段（如 <code>create_time</code>）不唯一，可能导致数据遗漏或重复。建议用 <code>ORDER BY create_time, id</code> 组合排序。</li><li><strong>子查询中 LIMIT 不支持的报错处理</strong>：MySQL 不允许在子查询中直接使用 LIMIT，需要多套一层 <code>SELECT id FROM (SELECT id FROM ... LIMIT ...) AS t</code>。</li><li><strong>大表定期归档数据</strong>：对于日志表、操作记录表等持续增长的大表，定期归档历史数据，从根源上控制数据量，避免深分页问题。</li></ol><h2 id="六、总结" tabindex="-1"><a class="header-anchor" href="#六、总结"><span>六、总结</span></a></h2><h3 id="_6-1-方案对比表" tabindex="-1"><a class="header-anchor" href="#_6-1-方案对比表"><span>6.1 方案对比表</span></a></h3><table><thead><tr><th>方案</th><th>原理</th><th>优点</th><th>缺点</th><th>适用场景</th><th>推荐指数</th></tr></thead><tbody><tr><td>子查询（延迟关联）</td><td>覆盖索引先查 ID，再回表</td><td>兼容性好，改动小</td><td>仍有大量扫描</td><td>后台管理（需跳页）</td><td>⭐⭐⭐⭐</td></tr><tr><td>INNER JOIN</td><td>同子查询，语法不同</td><td>可读性好</td><td>仍有大量扫描</td><td>后台管理（需跳页）</td><td>⭐⭐⭐⭐</td></tr><tr><td>游标分页</td><td>基于上次查询结果定位</td><td><strong>性能最优且稳定</strong></td><td>无法跳页</td><td>信息流、瀑布流</td><td>⭐⭐⭐⭐⭐</td></tr></tbody></table><h3 id="_6-2-行动清单" tabindex="-1"><a class="header-anchor" href="#_6-2-行动清单"><span>6.2 行动清单</span></a></h3><ol><li><strong>审计现有系统的深分页 SQL</strong>：搜索所有 <code>LIMIT</code> 语句，找出 offset 超过 1000 的查询。</li><li><strong>优先使用游标分页</strong>：对于信息流类需求，改用 <code>WHERE id &gt; cursor</code> 的游标方案。</li><li><strong>必须跳页时使用延迟关联</strong>：后台管理列表如果必须支持跳页，使用子查询或 JOIN 方案减少回表。</li><li><strong>建立分页查询规范</strong>：禁止 <code>LIMIT offset</code> 中 offset 超过 10000，超过时必须使用游标方案。</li><li><strong>合理设置索引</strong>：确保 <code>WHERE</code> + <code>ORDER BY</code> 的字段组合有合适的索引，避免 filesort。</li><li><strong>考虑搜索引擎方案</strong>：对于复杂的全文搜索和多维度分页，考虑引入 Elasticsearch，其深分页性能更优。</li><li><strong>监控慢查询日志</strong>：配置 <code>slow_query_log</code>，定期分析包含 <code>LIMIT</code> 的慢 SQL，持续优化。</li></ol>',7))])}const u=t(p,[["render",r],["__file","page.html.vue"]]),h=JSON.parse('{"path":"/mysql/page.html","title":"","lang":"zh-CN","frontmatter":{"description":"引言 用户投诉\\"APP 翻页越来越卡\\"，一查才发现：翻到第 1000 页时，一条简单的分页查询要跑 3 秒。 LIMIT 100000, 10——这条看似无害的 SQL，在数据量增长后变成了性能杀手。MySQL 需要先扫描并丢弃前 10 万条数据，才能返回你需要的 10 条。数据量越大，性能下降越剧烈。 深分页是所有业务系统的必经之路：后台管理列表、日...","head":[["meta",{"property":"og:url","content":"https://vuepress-theme-hope-docs-demo.netlify.app/mysql/page.html"}],["meta",{"property":"og:site_name","content":"Java八股文网"}],["meta",{"property":"og:description","content":"引言 用户投诉\\"APP 翻页越来越卡\\"，一查才发现：翻到第 1000 页时，一条简单的分页查询要跑 3 秒。 LIMIT 100000, 10——这条看似无害的 SQL，在数据量增长后变成了性能杀手。MySQL 需要先扫描并丢弃前 10 万条数据，才能返回你需要的 10 条。数据量越大，性能下降越剧烈。 深分页是所有业务系统的必经之路：后台管理列表、日..."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2026-04-18T07:28:17.000Z"}],["meta",{"property":"article:author","content":"Mr.Hope"}],["meta",{"property":"article:modified_time","content":"2026-04-18T07:28:17.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"\\",\\"image\\":[\\"\\"],\\"dateModified\\":\\"2026-04-18T07:28:17.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.Hope\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"引言","slug":"引言","link":"#引言","children":[]},{"level":2,"title":"一、深分页问题复现","slug":"一、深分页问题复现","link":"#一、深分页问题复现","children":[{"level":3,"title":"1.1 准备数据","slug":"_1-1-准备数据","link":"#_1-1-准备数据","children":[]},{"level":3,"title":"1.2 验证深分页问题","slug":"_1-2-验证深分页问题","link":"#_1-2-验证深分页问题","children":[]},{"level":3,"title":"1.3 性能下降的根源","slug":"_1-3-性能下降的根源","link":"#_1-3-性能下降的根源","children":[]},{"level":3,"title":"1.4 回表查询流程","slug":"_1-4-回表查询流程","link":"#_1-4-回表查询流程","children":[]}]},{"level":2,"title":"二、方案一：子查询优化（延迟关联）","slug":"二、方案一-子查询优化-延迟关联","link":"#二、方案一-子查询优化-延迟关联","children":[{"level":3,"title":"2.1 优化思路","slug":"_2-1-优化思路","link":"#_2-1-优化思路","children":[]},{"level":3,"title":"2.2 优化 SQL","slug":"_2-2-优化-sql","link":"#_2-2-优化-sql","children":[]},{"level":3,"title":"2.3 为什么能加速？","slug":"_2-3-为什么能加速","link":"#_2-3-为什么能加速","children":[]},{"level":3,"title":"2.4 流程图","slug":"_2-4-流程图","link":"#_2-4-流程图","children":[]}]},{"level":2,"title":"三、方案二：INNER JOIN 优化","slug":"三、方案二-inner-join-优化","link":"#三、方案二-inner-join-优化","children":[{"level":3,"title":"3.1 优化 SQL","slug":"_3-1-优化-sql","link":"#_3-1-优化-sql","children":[]},{"level":3,"title":"3.2 与子查询方案的对比","slug":"_3-2-与子查询方案的对比","link":"#_3-2-与子查询方案的对比","children":[]}]},{"level":2,"title":"四、方案三：分页游标（推荐）","slug":"四、方案三-分页游标-推荐","link":"#四、方案三-分页游标-推荐","children":[{"level":3,"title":"4.1 实现方式","slug":"_4-1-实现方式","link":"#_4-1-实现方式","children":[]},{"level":3,"title":"4.2 为什么性能最好？","slug":"_4-2-为什么性能最好","link":"#_4-2-为什么性能最好","children":[]},{"level":3,"title":"4.3 适用场景","slug":"_4-3-适用场景","link":"#_4-3-适用场景","children":[]},{"level":3,"title":"4.4 大厂实践","slug":"_4-4-大厂实践","link":"#_4-4-大厂实践","children":[]}]},{"level":2,"title":"五、生产环境避坑指南","slug":"五、生产环境避坑指南","link":"#五、生产环境避坑指南","children":[]},{"level":2,"title":"六、总结","slug":"六、总结","link":"#六、总结","children":[{"level":3,"title":"6.1 方案对比表","slug":"_6-1-方案对比表","link":"#_6-1-方案对比表","children":[]},{"level":3,"title":"6.2 行动清单","slug":"_6-2-行动清单","link":"#_6-2-行动清单","children":[]}]}],"git":{"createdTime":1745907928000,"updatedTime":1776497297000,"contributors":[{"name":"Yideng","email":"oointer@163.com","commits":2}]},"readingTime":{"minutes":7.42,"words":2225},"filePathRelative":"mysql/page.md","localizedDate":"2025年4月29日","autoDesc":true}');export{u as comp,h as data};
